// Before default parameters (old pattern):
function greet(name) {
  const displayName = name || 'World';
  return `Hello, ${displayName}!`;
}

// With default parameters (modern):
function greet(name = 'World') {
  return `Hello, ${name}!`;
}

greet('Alice'); // 'Hello, Alice!'
greet();        // 'Hello, World!'  — name defaults to 'World'
greet(undefined); // 'Hello, World!' — undefined triggers the default

function setVolume(level = 50) {
  console.log(level);
}

setVolume(0);         // 0   — 0 is used as-is (NOT replaced by 50)
setVolume(null);      // null — null is used as-is (NOT replaced by 50)
setVolume('');        // ''  — empty string is used as-is
setVolume(undefined); // 50  — undefined triggers the default
setVolume();          // 50  — missing arg is treated as undefined

// Expression as default
function createId(prefix = 'item', suffix = Date.now()) {
  return `${prefix}-${suffix}`;
}
createId();             // e.g. 'item-1710000000000'
createId('user');       // e.g. 'user-1710000000000'

// Function call as default
function getDefaultConfig() {
  return { theme: 'light', lang: 'en' };
}

function setup(config = getDefaultConfig()) {
  return config.theme;
}
setup();                // 'light'
setup({ theme: 'dark', lang: 'fr' }); // 'dark'

// Later parameters can reference earlier ones
function multiply(a, b = a) {
  return a * b;
}

multiply(3);    // 9  — b defaults to a (3 × 3)
multiply(3, 4); // 12 — b is 4 (3 × 4)

// ✅ Modern: default values in destructuring
function Button({
  label = 'Click me',
  variant = 'primary',
  size = 'medium',
  disabled = false,
  onClick,
}) {
  return (
    <button
      className={`btn btn-${variant} btn-${size}`}
      disabled={disabled}
      onClick={onClick}
    >
      {label}
    </button>
  );
}

// Using the component:
<Button onClick={handleSubmit} />                    // all defaults apply
<Button label="Save" variant="success" onClick={save} /> // overrides label and variant

// ⚠️ Default object/array in destructuring creates a new reference each render
function List({ items = [] }) {
  // items defaults to a NEW [] on every render if not provided
  // This is usually fine, but be aware if passing to React.memo children
  return <ul>{items.map((item, i) => <li key={i}>{item}</li>)}</ul>;
}

// For stable references, define the default outside the component:
const DEFAULT_ITEMS = [];
function List({ items = DEFAULT_ITEMS }) {
  return <ul>{items.map((item, i) => <li key={i}>{item}</li>)}</ul>;
}

// Default to a no-op function so you can call it without checking first
function Input({ value, onChange = () => {} }) {
  return <input value={value} onChange={onChange} />;
}

// Now you can always call onChange safely:
function handleKeyDown(e) {
  if (e.key === 'Enter') {
    onChange(value); // no need for onChange && onChange(value)
  }
}

// Extract known props with defaults, pass remaining to the DOM element
function TextInput({
  label = 'Input',
  placeholder = '',
  disabled = false,
  ...rest // contains any other props like className, id, name, etc.
}) {
  return (
    <div>
      <label>{label}</label>
      <input
        placeholder={placeholder}
        disabled={disabled}
        {...rest}
      />
    </div>
  );
}

// ❌ || replaces 0 and false — valid values get overridden
function setOpacity(value) {
  const opacity = value || 1; // if value is 0 → 1 (wrong!)
}

// ✅ Default parameter only replaces undefined
function setOpacity(value = 1) {
  // if value is 0 → 0 (correct)
  // if value is undefined or not passed → 1 (correct)
}

// ❌ Bad — the required param after the default creates confusion
function connect(timeout = 5000, host) {
  // To use the default timeout, caller must pass undefined:
  connect(undefined, 'localhost'); // awkward!
}

// ✅ Put required parameters first, optional ones with defaults last
function connect(host, timeout = 5000) {
  // connect('localhost')       — uses default timeout 5000
  // connect('localhost', 3000) — uses custom timeout 3000
}

function format(value = 'N/A') {
  return value;
}

format(null);      // null  — default NOT triggered (null ≠ undefined)
format(undefined); // 'N/A' — default triggered

// If null should also trigger the default, handle it explicitly:
function format(value = undefined) {
  return value ?? 'N/A'; // ?? falls back for both null and undefined
}
